import type {ArticleSection} from '../types/philosophy';

const section=(id:string,title:string,paragraphs:string[],relatedBranchIds?:string[],relatedPhilosopherIds?:string[],relatedWorkTitles?:string[]):ArticleSection=>({id,title,paragraphs,relatedBranchIds,relatedPhilosopherIds,relatedWorkTitles});

export const lateAntiqueInheritancePhilosopherArticles:Record<string,ArticleSection[]>={
  plotinus:[
    section('overview','A systematic Platonist at the center of late antique philosophy',[
      'Plotinus is the central figure in the philosophical movement later called Neoplatonism. He did not understand himself as inventing a philosophy after Plato or replacing the dialogues with mysticism. He presented his work as an interpretation and defense of Platonism capable of answering questions sharpened by Aristotle, Stoicism, skepticism, and centuries of debate within the Platonic tradition. His account orders reality through the One, Intellect, and Soul, while treating philosophical life as a movement from distracted identification with sensible things toward clearer awareness of intelligible source and unity.',
      'The resulting philosophy is both systematic and exploratory. Plotinus argues about causation, identity, thought, freedom, time, beauty, matter, evil, and the structure of living beings. He also describes rare experiences of union with the first principle, which is beyond ordinary thought and predication. Treating him only as a mystical Platonist loses the arguments that make ascent intelligible; treating him only as a metaphysician loses the practical transformation those arguments seek. Plotinus asks what reality must be like for plurality, intelligence, life, and individual striving to arise without severing themselves from a source of unity.'
    ],['neoplatonism','platonism','metaphysics'],['plotinus','plato','aristotle'],['Enneads']),
    section('context','Late antique philosophy and the pressure to synthesize',[
      'Plotinus lived in the third-century Roman Empire, a period of political instability, religious plurality, and highly developed philosophical schools. Platonists had long debated how to organize Plato’s dialogues into a coherent account of reality and the good. Aristotle’s categories, psychology, logic, and metaphysics had become unavoidable resources even for thinkers who rejected parts of his criticism of Plato. Stoic accounts of corporeal nature, providence, and soul offered powerful rivals. Christian and Gnostic movements also proposed accounts of creation, salvation, and the value of the sensible world.',
      'This context makes Plotinus’ philosophy an intervention rather than an isolated vision. He defends intelligible reality against materialism, but he also rejects a crude dualism that treats the physical cosmos as the evil product of a failed power. He uses Aristotelian distinctions while denying that Intellect can be reduced to an individual faculty. He shares Stoic concern for cosmic unity while rejecting the claim that only bodies are fully real. The architecture of One, Intellect, and Soul is designed to explain how reality can be ordered, alive, and intelligible without making its first principle one being among others.'
    ],['neoplatonism','platonism','aristotelianism','stoicism'],['plotinus','plato','aristotle'],['Enneads']),
    section('life-school','Life, teaching, and philosophical community',[
      'Most biographical information comes from Porphyry’s Life of Plotinus, written by a devoted student who also edited the Enneads. Plotinus was born around 204 CE, studied in Alexandria with Ammonius Saccas, and later taught in Rome. Porphyry portrays him as personally modest, attentive to students and dependents, uninterested in portraiture, and deeply committed to contemplation. These details are shaped to present a philosophical character and must be read accordingly, but they also show that Plotinian ascent did not simply mean withdrawal from ordinary responsibility.',
      'Plotinus taught through seminars and responses to questions rather than by presenting a single finished textbook. His circle included people with different backgrounds and practical concerns. He reportedly considered establishing a philosophically governed community, though the plan was never realized. The social setting matters because the Enneads can sound solitary when read as meditations on inward ascent. Their arguments arose within teaching, disagreement, commentary, and care. Philosophical purification directs attention beyond status and possession, but it does not require contempt for embodied people or abandonment of the relations through which inquiry becomes possible.'
    ],['neoplatonism','ethics','ancient-greek'],['plotinus'],['Life of Plotinus','Enneads']),
    section('porphyry','Porphyry and the making of the Enneads',[
      'Plotinus did not publish the Enneads in their familiar order. Porphyry collected fifty-four treatises, edited them, and arranged them into six groups of nine, giving the work its name. The arrangement moves broadly from ethical and human questions through nature, soul, Intellect, and the One, but it is not a chronological record of Plotinus’ development. Porphyry also supplied titles and a biography. Every modern reader therefore encounters Plotinus through a student’s powerful editorial act.',
      'The treatises retain traces of their original occasions. A question is posed, an inherited claim is tested, an opponent is answered, or a line from Plato becomes the starting point for sustained analysis. Apparent repetitions often show Plotinus approaching the same structure from a different problem. Reading the Enneads as one linear system can conceal this argumentative motion, while reading them as disconnected mystical essays loses their coherence. Porphyry’s arrangement is best used as a map that makes connections visible without erasing chronology, occasion, or unresolved tension.'
    ],['neoplatonism','platonism'],['plotinus'],['Enneads','Life of Plotinus']),
    section('one','The One beyond being and thought',[
      'The first principle is called the One or the Good because every being and every intelligible structure depends on unity. A thing that lacked all unity would not be one thing at all, and a complex explanation seems to depend on parts and principles more basic than itself. Plotinus therefore argues toward a source that is not composite, limited, or dependent. The One cannot be an ordinary being with properties, because that would introduce multiplicity into the principle meant to explain all multiplicity. It is described as beyond being and beyond thought.',
      'Negative language does not mean the One is empty or unreal. It marks the failure of predicates suited to determinate things. Even calling it a cause risks imagining an agent deciding among options. Plotinus instead presents the One as superabundant perfection from which other reality depends without diminishing its source. This raises difficult questions. How can anything be said about what exceeds thought? How can a principle without multiplicity explain plurality? Plotinus answers indirectly through effects, dependence, and the limits encountered when intellect seeks its own source. Negative theology later develops from this disciplined refusal to make first principle into an object.'
    ],['neoplatonism','metaphysics','philosophy-of-religion'],['plotinus','plato','pseudo-dionysius'],['Enneads']),
    section('intellect','Intellect, Forms, and thinking that is being',[
      'Intellect is the first determinate level of reality after the One. It contains the Platonic Forms not as external objects viewed from elsewhere but as a living intelligible whole. In genuine intellectual knowledge, thinker and object are distinct enough for thought yet united enough to avoid the gap and uncertainty characteristic of sensory cognition. Intellect is therefore both being and thought: the ordered plurality of intelligible realities understanding itself. Plotinus uses this structure to explain why Forms are not inert models and why knowledge can disclose reality rather than merely represent it from a distance.',
      'This account transforms both Plato and Aristotle. Plato’s intelligible standards become internally articulated within divine Intellect. Aristotle’s thinking that thinks itself helps explain perfect intellectual activity, but Plotinus multiplies the content of that activity through the Forms. Intellect remains dependent on the One because its self-understanding contains plurality. The distinction allows Plotinus to explain how determinate being arises while preserving a source beyond determination. It also gives philosophical contemplation an ontological meaning: to understand intelligible structure is for the soul to participate more fully in the level of reality from which its rational activity derives.'
    ],['neoplatonism','platonism','aristotelianism','epistemology'],['plotinus','plato','aristotle'],['Enneads','Metaphysics']),
    section('soul','Soul, nature, and presence without division',[
      'Soul proceeds from Intellect and mediates intelligible order to the sensible cosmos. It is not a body located in one place or a material substance cut into pieces among organisms. Plotinus argues that soul can be present throughout a living body without being divided as body is divided. Universal Soul orders the cosmos, while individual souls possess their own activity and relation to Intellect. Nature names a lower contemplative power through which living forms unfold without deliberate calculation. The sensible world is therefore dynamic expression, not dead matter externally assembled.',
      'The soul’s descent should not be imagined only as a historical fall from a place above. Soul remains rooted in intelligible reality even while attention becomes absorbed in bodily life, possession, and fragmented concern. Ascent is possible because the source has not been completely abandoned. This account avoids simplistic dualism: embodiment can distract, constrain, and expose souls to suffering, but the ordered cosmos is beautiful and its living forms express intelligible principles. Plotinus’ challenge is to explain individuality and moral responsibility when souls remain connected to universal sources more deeply than ordinary self-awareness recognizes.'
    ],['neoplatonism','philosophy-of-mind','metaphysics'],['plotinus'],['Enneads']),
    section('procession-return','Procession and return without a temporal creation story',[
      'Later readers often describe Plotinian reality through emanation. The term can be helpful if it indicates dependence that does not deplete its source, but it can mislead when it suggests material fluid spreading outward or a sequence of events in time. Procession names the way a more multiple and determinate level depends on a prior unity. The One does not first exist alone and then choose to produce Intellect. Intellect and Soul depend eternally on their sources, and the sensible cosmos expresses Soul’s ordering activity.',
      'Return complements procession. Each level seeks its source and becomes itself through orientation toward what is prior. Intellect turns toward the One and constitutes intelligible thought; Soul turns toward Intellect and orders life; a human being turns inward and upward through ethical purification, dialectic, and contemplation. Return is not escape from reality but clearer participation in its structure. The paired movement explains how dependence can generate activity rather than passivity. What proceeds is not cut off, and what returns does not erase its distinct level. The difficulty is determining how much genuine individuality survives the movement toward unity.'
    ],['neoplatonism','metaphysics','platonism'],['plotinus'],['Enneads']),
    section('evil-matter','Evil, matter, and the refusal of a rival principle',[
      'Plotinus refuses to make evil an independent power equal to the Good. Evil is associated with privation, deficiency, disorder, and the extreme limit represented by matter without form. This account protects the priority of the Good: what exists and acts possesses some unity and form, while evil lacks the positive self-sufficiency required of a first principle. Moral evil arises when soul becomes disordered through attachment to lower goods and forgetfulness of its rational source, not because embodiment is the creation of an evil god.',
      'The theory faces serious pressure. Suffering and wrongdoing can seem too positive and destructive to be described as mere absence. Calling matter evil risks reviving the anti-body dualism Plotinus rejects, especially when bodies depend on matter. Plotinus distinguishes the beauty and order of the formed cosmos from formless deficiency, but interpreters dispute how successfully the distinction works. His argument remains influential because it changes the question from what substance evil is to how good powers and desires become limited, disordered, or turned away from their proper measure.'
    ],['neoplatonism','ethics','metaphysics','philosophy-of-religion'],['plotinus','augustine'],['Enneads']),
    section('beauty','Beauty and the soul’s recognition of form',[
      'Plotinus rejects the idea that beauty is simply symmetry among bodily parts. A simple color or flash of light can be beautiful, and a well-proportioned object can fail to move a perceiver. Beauty appears when form gives unity and intelligibility to what would otherwise be dispersed. The soul recognizes something akin to its own intelligible source and is awakened by that recognition. Sensible beauty is therefore neither an illusion nor the final object of desire. It is a trace that can redirect attention toward the formative activity it expresses.',
      'The ascent through beauty transforms the perceiver as well as the object of attention. Plotinus asks the soul to become beautiful by removing disorder, comparing ethical purification to shaping a statue. The image can sound like discovery of a ready-made inner essence, but it also emphasizes work: habits, desires, and judgments must be reordered. Art is not merely an inferior copy of sensible objects. Because an artist can work from intelligible form, artistic making may reveal order more clearly than a particular natural object. Plotinus thereby extends Platonic beauty into aesthetics, ethics, and contemplative practice.'
    ],['neoplatonism','aesthetics','ethics'],['plotinus','plato'],['Enneads']),
    section('practice','Philosophical practice, contemplation, and union',[
      'Plotinian practice begins with ethical virtues that order action and limit domination by appetite, but it does not end there. Purification loosens mistaken identification with bodily possession and social status. Dialectic turns the mind toward intelligible relations. Contemplation becomes awareness of Intellect’s living unity, and rare union with the One exceeds the ordinary distinction between knower and known. Porphyry reports such experiences, but their philosophical meaning depends on the metaphysical argument that the soul’s deepest source cannot be grasped as one object among others.',
      'Union is often called mystical, a useful term if it marks an experience that exceeds discursive thought. It becomes misleading when it suggests irrational feeling, private revelation detached from argument, or permanent disappearance of the person. Plotinus writes because analysis and disciplined life prepare and interpret ascent, even if the first principle cannot be captured propositionally. After moments of unity, ordinary differentiated life continues. The tension between union and individuality remains unresolved and productive. Does highest fulfillment perfect the self, disclose a deeper self, or temporarily pass beyond the structures through which individuality is known?'
    ],['neoplatonism','ethics','philosophy-of-religion'],['plotinus'],['Enneads','Life of Plotinus']),
    section('against-materialism','Against materialism and simplistic dualism',[
      'Plotinus argues that bodies and bodily states cannot by themselves explain unity, life, perception, and thought. A body is divisible, while a living organism functions as one coordinated whole; sensory information from different organs is compared within unified awareness; intellectual truths are not exhausted by the changing physical instances that occasion thought. These arguments target Stoic corporealism and other materialist accounts. They do not resemble modern scientific arguments exactly, but they press a durable question: what kind of explanation accounts for organization and intelligibility rather than merely listing material components?',
      'At the same time, Plotinus rejects the idea that the sensible cosmos is simply a prison or mistake. Against Gnostic opponents, he defends its order and beauty as the work of Soul. The problem is not body as such but a soul’s false belief that bodily possession exhausts its identity and good. This double opposition is essential. Plotinus is neither a crude materialist nor a simple anti-world dualist. He seeks a layered natural order in which bodies are real expressions of form, while the principles that make unity, life, and thought possible are not reducible to bodies.'
    ],['neoplatonism','philosophy-of-mind','metaphysics','stoicism'],['plotinus'],['Enneads']),
    section('reception','Christian, Islamic, Jewish, and Renaissance transformations',[
      'Plotinus’ influence traveled through later Neoplatonists and through texts whose identities changed in transmission. Augustine adapted Platonic inwardness, immaterial truth, and privation of evil within Christian creation and grace. Pseudo-Dionysius transformed hierarchy, procession, return, and negative theology. In Arabic philosophy, a paraphrase of parts of the Enneads circulated as the Theology of Aristotle, encouraging attempts to read Aristotelian and Neoplatonic metaphysics together. Islamic and Jewish thinkers adapted themes of intellect, causation, unity, and negative predication in distinctive theological settings.',
      'Renaissance Platonists renewed direct engagement with Plotinus, and later idealists, metaphysicians, theologians, artists, and writers continued to draw on him. Influence should not be described as simple repetition. Creation from nothing differs from eternal procession; a personal providential God differs from the One beyond Intellect; resurrection and covenant create questions absent from Plotinus. His importance lies partly in supplying an architecture flexible enough to be transformed. Unity, participation, inward ascent, and negative theology become shared problems across traditions precisely because each inheritance revises what it receives.'
    ],['neoplatonism','philosophy-of-religion','islamic-philosophy','platonism'],['plotinus','augustine','pseudo-dionysius','avicenna'],['Enneads','Confessions','Mystical Theology']),
    section('reading','How to read Plotinus',[
      'Begin with treatises on beauty, the virtues, and the three principal levels of reality, using an edition that preserves Ennead location and chronological information. Read Porphyry’s Life as an interpretive portrait rather than neutral biography. When Plotinus invokes Plato, locate the dialogue and ask what transformation has occurred. When he uses Aristotelian language, notice whether the borrowed distinction is being placed inside a different metaphysical order. The Enneads reward movement among treatises because a problem such as soul, matter, or contemplation changes when approached from another level.',
      'Keep four cautions in view. Emanation is dependence, not a material spill in time. The One is not simply the largest being. Ascent does not make the sensible cosmos worthless. Mystical union does not replace argument with vagueness. Plotinus matters because his philosophy makes metaphysics answerable to a practice of attention while making contemplative claims answerable to argument. The best reading asks both what structure explains plurality and what transformation would allow a person to recognize participation in that structure more clearly.'
    ],['neoplatonism','platonism','metaphysics'],['plotinus','plato','aristotle'],['Enneads','Life of Plotinus'])
  ]
};

export const lateAntiqueInheritanceBranchArticles:Record<string,ArticleSection[]>={
  aristotelianism:[
    section('overview','An inheritance organized around inquiry, not repetition',[
      'Aristotelianism is the long, internally diverse tradition that develops from Aristotle’s works, methods, school, and questions. It cannot be reduced to agreeing with everything Aristotle wrote. The corpus ranges across logic, metaphysics, natural philosophy, biology, psychology, ethics, politics, rhetoric, and poetics, often leaving tensions that later readers had to interpret. To inherit Aristotle is to ask how different kinds of explanation fit a structured natural world, how concepts answer to things, and how disciplined inquiry should adapt its method to its subject.',
      'The tradition repeatedly transforms as it crosses institutions and languages. Early Peripatetics extend research in the Lyceum. Late antique commentators organize texts and reconcile or distinguish Aristotle from Plato. Islamic philosophers build new metaphysical and psychological systems through translation and criticism. Jewish and Christian thinkers adapt Aristotelian tools to theology and law. Renaissance and early modern natural philosophy reject major parts of the physics while retaining causal, logical, and biological problems. Contemporary revivals return to virtue, powers, form, action, and organism without simply restoring an ancient worldview.'
    ],['aristotelianism','metaphysics','logic','ethics'],['aristotle','averroes','aquinas'],['Categories','Metaphysics','Nicomachean Ethics']),
    section('lyceum','Aristotle, the Lyceum, and organized research',[
      'Aristotle studied in Plato’s Academy for roughly two decades before developing positions that criticize separate Forms and relocate explanation within concrete substances. He later taught at the Lyceum in Athens. The Peripatetic school associated philosophical argument with collection, classification, observation, and collaborative research. Studies of constitutions, animals, dramatic forms, argument types, and earlier thinkers all belong to the same broad effort: identify the principles appropriate to a domain rather than forcing every subject into one method.',
      'The surviving corpus is not a polished set of books written for modern readers. Many texts appear connected with teaching and have layered histories. Their compressed arguments, cross-references, repetitions, and unresolved questions created the need for commentary from the beginning. The Lyceum therefore matters not only as the origin of doctrines but as an institutional model of inquiry. Aristotelianism inherits a practice of distinguishing sciences, gathering appearances and reputable opinions, analyzing causes, and revising concepts through sustained attention to the kinds of beings under study.'
    ],['aristotelianism','ancient-greek','philosophy-of-science'],['aristotle','plato'],['Metaphysics','History of Animals','Politics']),
    section('logic-categories','Logic, categories, and demonstrative knowledge',[
      'Aristotle’s logical works, later grouped as the Organon, analyze terms, propositions, syllogisms, demonstration, dialectical argument, and fallacy. A syllogism shows how a conclusion follows necessarily from premises of certain forms. Demonstrative science requires more than valid inference: premises must be true, explanatory, and appropriately prior to the conclusion. The Categories examines fundamental ways things are said and kinds of being such as substance, quantity, quality, relation, and place. These tools became central to ancient, Islamic, Jewish, Christian, and university education.',
      'Aristotelian logic was never only a mechanical rulebook. It raises questions about how language, thought, and reality correspond; what makes a premise explanatory rather than merely true; and how first principles can be known if demonstrations depend on them. Later traditions expanded, reorganized, and criticized the framework. Stoic propositional logic offered a different ancient route, and modern logic transformed formal analysis. Yet Aristotelian distinctions remain philosophically active whenever inquiry asks what kind of thing is being discussed, which predicates belong essentially, and why a conclusion follows.'
    ],['aristotelianism','logic','epistemology'],['aristotle','chrysippus','averroes'],['Categories','Prior Analytics','Posterior Analytics']),
    section('substance','Substance, form, matter, and change',[
      'Aristotelian metaphysics begins from concrete beings that persist and change. Substance names what exists in a primary way and supports predication, but Aristotle’s treatments generate difficult questions about whether substance is the individual composite, its form, or some relation among form, matter, and essence. Hylomorphism explains a natural thing as matter organized by form. Form is not merely visible shape; it is the intelligible organization and activity through which matter constitutes this kind of living or nonliving thing.',
      'Potentiality and actuality explain change without treating it as emergence from absolute nothing or as mere appearance. A capacity can be real without already being exercised, and change is the actualization of what is possible under appropriate conditions. These distinctions became central to accounts of causation, soul, creation, sacrament, action, and natural powers. They also invite criticism. Does form explain or redescribe organization? Can substances be reconciled with modern physics? Aristotelianism persists partly because it offers a vocabulary for structured beings and capacities that neither atomistic composition nor purely external relations obviously captures.'
    ],['aristotelianism','metaphysics','ontology'],['aristotle','aquinas'],['Physics','Metaphysics']),
    section('causes','Four causes and the scope of explanation',[
      'Aristotle distinguishes material, formal, efficient, and final causes. To explain a statue, one may identify its bronze, its organizing form, the maker’s activity, and the end for which it was made. Natural beings complicate the example because their development and characteristic activities arise from internal principles rather than an external artisan. A full account of an organism may ask what it is made from, how development occurs, what organization makes it this kind of living thing, and which mature activities its capacities characteristically support.',
      'Final causation became one of the most contested Aristotelian commitments. Critics often interpret it as the claim that every event serves a conscious cosmic plan. Aristotelian accounts can instead treat ends as immanent to organized activities: eyes are for seeing because sight explains their structure and successful functioning. Mechanistic science challenged explanations that seemed to substitute purposes for efficient processes, but contemporary philosophy of biology still debates function, organization, and goal-directed behavior. The tradition’s strongest claim is methodological: different why-questions may require different but compatible kinds of answer.'
    ],['aristotelianism','metaphysics','philosophy-of-science'],['aristotle'],['Physics','Parts of Animals']),
    section('nature-soul','Natural philosophy, biology, and soul',[
      'Aristotle’s natural works investigate motion, place, time, generation, elements, living things, and causal order. Many specific physical claims are scientifically obsolete, but the project is not mere speculation detached from observation. Biological works compare anatomy, reproduction, development, behavior, and environmental adaptation across animals. They seek organized explanations while also carrying the limitations and hierarchies of ancient inquiry. Aristotelianism inherits both the ambition to understand living forms and the obligation to separate productive concepts from failed empirical claims.',
      'In De Anima, soul is the form and actuality of a living body, not simply a separate occupant controlling a machine. Nutritive, perceptive, locomotive, and rational capacities describe kinds of life and activity. This hylomorphic psychology can resist both reductive materialism and a simple substance dualism, but Aristotle’s remarks on intellect are famously difficult. Later Greek, Islamic, Jewish, and Christian thinkers disagreed over whether intellect is individual, shared, material, or separable. Those disputes made Aristotelian psychology a central route into questions of consciousness, personal survival, and knowledge.'
    ],['aristotelianism','philosophy-of-science','philosophy-of-mind'],['aristotle','avicenna','averroes','aquinas'],['Physics','De Anima','History of Animals']),
    section('practical-arts','Ethics, politics, rhetoric, and poetics',[
      'Aristotelian practical philosophy asks how people become capable of acting well across variable circumstances. The Nicomachean Ethics treats flourishing as excellent activity across a complete life, shaped by habituated virtues, emotion, friendship, and practical wisdom. Virtue is not mechanical rule-following or spontaneous authenticity. It is a trained disposition to perceive and choose well, with attention to context and reasons. Politics extends the inquiry because laws, education, economic arrangements, and forms of rule help form the character and opportunities through which citizens act.',
      'Rhetoric and poetics show Aristotelian analysis applied to persuasive speech and dramatic making. Rhetoric studies how character, emotion, and argument operate where strict demonstration is unavailable. Poetics analyzes how plot, recognition, reversal, character, and representation structure tragedy. These works prevent Aristotelianism from being only a metaphysics of substance. They examine practices whose success depends on formal organization and responsive judgment. Later traditions use them to ask how ethical formation, political institutions, public reasoning, and art shape what people can perceive as possible or worthwhile.'
    ],['aristotelianism','ethics','political-philosophy','aesthetics'],['aristotle','aquinas'],['Nicomachean Ethics','Politics','Rhetoric','Poetics']),
    section('peripatetics-commentators','Peripatetics and the late antique commentary tradition',[
      'After Aristotle, the Peripatetic school did not simply preserve a complete system unchanged. Theophrastus and other early successors extended natural inquiry, ethics, logic, and the study of character while debating the founder’s positions. Over time, Aristotle’s writings required recovery, organization, and interpretation. Commentators asked how apparently conflicting passages fit together, how technical terms should be understood, and whether Aristotelian conclusions could be reconciled with Platonic metaphysics. Commentary became a major form of philosophical production rather than a secondary activity.',
      'Late antique commentators developed problems that would travel far beyond their schools. They clarified categories, causation, universals, intellect, and the relation among philosophical sciences. Some sought harmony between Plato and Aristotle; others emphasized disagreement. Their questions and teaching structures shaped the texts translated into Syriac and Arabic and later into Latin. Aristotelianism therefore grows through acts of reading that are also acts of construction. Deciding the order of study, resolving an ambiguity, or distinguishing Aristotle’s claim from a later interpretation can redirect an entire inherited system.'
    ],['aristotelianism','platonism','ancient-greek'],['aristotle','plotinus'],['Categories','Metaphysics','De Anima']),
    section('islamic','Al-Farabi, Avicenna, Averroes, and Islamic Aristotelianisms',[
      'The translation movement into Arabic made works of Aristotle and the commentary tradition available within new intellectual settings. Al-Farabi organized the sciences and joined logic, metaphysics, and political philosophy. Avicenna built a powerful system that distinguishes essence from existence and analyzes necessary and possible being, intellect, soul, and demonstration. His philosophy is deeply engaged with Aristotle but cannot be reduced to commentary. It reshaped the questions that later Islamic, Jewish, and Christian thinkers encountered.',
      'Averroes became famous for detailed commentaries defending Aristotle against interpretations he considered distortions, yet his own work addresses law, theology, intellect, and the legitimacy of philosophical demonstration. The label Islamic Aristotelianism therefore names multiple projects, not a single school obedient to a Greek authority. Translation, commentary, criticism, and systematic invention interact. These philosophers changed Aristotelian metaphysics and psychology while asking how demonstrative reasoning relates to revelation and religious community. Their work later transformed Latin and Jewish philosophy as well as debates within Islamic traditions.'
    ],['aristotelianism','islamic-philosophy','metaphysics'],['al-farabi','avicenna','averroes'],['The Cure','Decisive Treatise']),
    section('jewish-christian','Maimonides, Aquinas, and theological transformation',[
      'Maimonides uses Aristotelian philosophy within a Jewish intellectual and legal world while carefully marking the limits of demonstration. The Guide for the Perplexed addresses readers troubled by apparent conflict between philosophical reasoning and scriptural language. Negative theology, creation, providence, prophecy, and law become sites where Aristotelian concepts are adopted, tested, and revised. Maimonides’ influence shows why inheriting Aristotle never meant merely adding religious conclusions to an untouched philosophical base.',
      'Aquinas likewise integrates Aristotelian form, matter, causation, act, potency, virtue, and natural law within Christian theology, while distinguishing philosophical argument from revealed doctrine. He rejects some interpretations of Aristotle and Averroes, especially concerning intellect and personal immortality. The scholastic setting turns disputed questions, objections, distinctions, and replies into a disciplined method. Jewish and Christian Aristotelianisms demonstrate that synthesis produces new systems with their own commitments. Creation, divine freedom, resurrection, and grace alter how Aristotelian nature and causation can be understood.'
    ],['aristotelianism','medieval-scholasticism','philosophy-of-religion'],['maimonides','aquinas','averroes'],['Guide for the Perplexed','Summa Theologiae']),
    section('scholastic-method','Scholastic method and the university inheritance',[
      'Medieval universities made Aristotelian works central to advanced education, especially in logic and natural philosophy. Scholastic method organized inquiry through authoritative texts, disputed questions, objections, distinctions, and replies. This structure is sometimes caricatured as submission to authority. In practice, it created techniques for stating opposing arguments precisely, identifying ambiguity, and explaining why a conclusion follows under one distinction but not another. Aristotle became authoritative partly because his works generated problems that could sustain rigorous institutional debate.',
      'Authority also created constraints and conflicts. Aristotelian conclusions could appear inconsistent with theological commitments, and condemnations or curricular rules shaped what could be taught. Different schools disputed universals, individuation, causation, intellect, will, and divine knowledge. Nominalist and voluntarist challenges exposed tensions within inherited frameworks. Scholastic Aristotelianism matters less as a single medieval worldview than as a durable culture of structured disagreement. Its legacy survives whenever philosophical education treats objections as resources and demands that a position answer the strongest available formulation of a rival.'
    ],['aristotelianism','medieval-scholasticism','logic'],['aquinas','ockham'],['Summa Theologiae']),
    section('challenges-revivals','Renaissance challenges and modern revivals',[
      'Renaissance humanists criticized scholastic language and returned to Greek texts, while new anatomy, astronomy, mechanics, and experimental practices challenged Aristotelian natural philosophy. Early modern thinkers rejected substantial forms, final causes, or inherited categories in favor of mathematical and mechanistic explanation. The decline of Aristotelian physics was a genuine transformation, but it did not eliminate every Aristotelian problem. Scientific inquiry still had to explain organisms, powers, causes, categories, inference, and the relation between observation and explanatory structure.',
      'Modern revivals are selective and diverse. Virtue ethics returns to character, flourishing, habituation, emotion, and practical wisdom. Neo-Aristotelian metaphysics develops accounts of powers, grounding, substances, and hylomorphic structure. Philosophy of biology revisits organism and function without restoring ancient cosmology. Action theory asks how reasons, capacities, and ends explain what agents do. These projects are Aristotelian when they use or transform the tradition’s questions and distinctions, not when they accept an entire historical package. The living inheritance is a method of seeking structured explanation across irreducibly different domains.'
    ],['aristotelianism','virtue-ethics','metaphysics','philosophy-of-science'],['aristotle','anscombe'],['Nicomachean Ethics','Metaphysics']),
    section('rivals-reading','Rivals, misunderstandings, and how to read the tradition',[
      'Platonists challenge Aristotelian accounts of immanent form and the highest principle; atomists and mechanists question substances, qualities, and final causes; nominalists resist realist accounts of universals; empiricists challenge claims about necessary structure; contemporary naturalists ask whether hylomorphism adds anything to scientific explanation. Aristotelians reply in different ways, which is why the tradition cannot be identified with one answer. Its history is an argument over what counts as an adequate explanation of a structured, changing, intelligible world.',
      'Begin with selected works of Aristotle in different domains rather than only the Metaphysics. The Categories, Nicomachean Ethics, De Anima, Poetics, and biological writings reveal the range of method. Then compare major transformations in Avicenna, Averroes, Maimonides, and Aquinas, keeping their theological and institutional contexts distinct. Finally examine a modern revival alongside a modern rejection. The central reading question is not whether Aristotle was right about everything. It is which explanatory distinctions remain useful, which became obstacles, and why later thinkers repeatedly found that rejecting Aristotle required learning how to ask his questions differently.'
    ],['aristotelianism','platonism','metaphysics','empiricism'],['aristotle','avicenna','averroes','maimonides','aquinas'],['Categories','De Anima','Nicomachean Ethics','Metaphysics'])
  ],
  neoplatonism:[
    section('overview','A later name for a transforming Platonic tradition',[
      'Neoplatonism is the modern name for a late antique philosophical movement whose members usually understood themselves simply as Platonists. The label helps distinguish Plotinus, Porphyry, Iamblichus, Proclus, and related thinkers from Plato and earlier Platonists, but it can falsely suggest that they knowingly founded a new school. They interpreted Plato through centuries of argument, drew extensively on Aristotle, answered Stoic and skeptical rivals, and developed a highly articulated metaphysics of the One, Intellect, Soul, procession, participation, and return.',
      'The tradition joins explanation to transformation. Metaphysics asks how plurality depends on unity and how lower levels of reality express higher principles without severing themselves from their source. Philosophical practice asks how a soul dispersed among appetites, roles, and sensible objects can become attentive to the intelligible order in which it participates. Later Neoplatonists disagree about ritual, hierarchy, the structure of divine principles, and the relation between Plato and Aristotle. Neoplatonism is therefore not vague mysticism or one doctrine of emanation. It is a sustained program for connecting logic, metaphysics, cosmology, ethics, religion, and contemplative practice.'
    ],['neoplatonism','platonism','metaphysics','philosophy-of-religion'],['plotinus','plato','augustine'],['Enneads']),
    section('label-context','Why the label came later',[
      'The term Neoplatonism was created long after antiquity to classify a development within the Platonic tradition. Ancient participants claimed continuity with Plato and often treated apparent innovations as faithful interpretation. Their confidence rested partly on a way of reading dialogues as pieces of an underlying philosophical order. Texts such as the Parmenides, Republic, Timaeus, Symposium, and Phaedrus supplied problems of unity, intelligibility, cosmos, beauty, and ascent that later Platonists organized systematically.',
      'Calling the movement later Platonism can emphasize continuity, while Neoplatonism usefully marks transformation. Plotinus’ One beyond being, the ordering of Forms within Intellect, elaborate levels of divine reality, and later theurgical practices cannot simply be read from one Platonic dialogue. They emerge through debate with Aristotle, Stoicism, religious practice, and earlier commentators. The label is most useful when it identifies a historical conversation without implying that all members agreed or that their philosophy was a decorative afterlife of Plato. They changed what Platonism could explain and how philosophical life could be practiced.'
    ],['neoplatonism','platonism','ancient-greek'],['plato','plotinus'],['Parmenides','Republic','Timaeus']),
    section('plotinus-enneads','Plotinus and the argumentative center of the Enneads',[
      'Plotinus gives the movement its foundational architecture. His treatises argue that determinate being and thought depend on Intellect, that Intellect’s ordered plurality depends on the One, and that Soul mediates intelligible form to living sensible reality. Porphyry edited the treatises into the Enneads and supplied a biography that shaped Plotinus’ reception. The texts combine close engagement with predecessors, original argument, ethical exhortation, and descriptions of contemplative union. They are neither a single textbook nor a loose collection of spiritual reflections.',
      'Plotinus establishes several enduring Neoplatonic commitments while leaving questions later thinkers would elaborate differently. Procession does not diminish the source; return allows each level to become itself through orientation to what is prior; evil lacks independent first-principle status; and the sensible cosmos remains beautiful despite deficiency. Later Neoplatonists systematize more levels and emphasize ritual practices that Plotinus does not foreground. Plotinus therefore stands at the center without exhausting the tradition. His work supplies a demanding standard against which later claims about divine hierarchy, interpretation, and ascent can be measured.'
    ],['neoplatonism','platonism','metaphysics'],['plotinus'],['Enneads','Life of Plotinus']),
    section('later-school','Porphyry, Iamblichus, Proclus, and school development',[
      'Porphyry preserved Plotinus, wrote across philosophy and religion, and helped make Aristotelian logic part of the Platonic curriculum. His Introduction to Aristotle’s Categories generated the later problem of universals by asking how genera and species exist. Iamblichus developed a more elaborate hierarchy and argued that human ascent requires theurgy, divinely grounded ritual action, because discursive intellect alone cannot cross every distance between embodied souls and divine causes. The shift makes ritual and traditional religious practice philosophically central.',
      'Proclus produced one of the tradition’s most systematic expressions, analyzing procession and return through recurring structures and articulating complex orders of causation and participation. Neoplatonic schools also became institutions of commentary, education, and religious identity in changing political circumstances. Disagreement among these figures matters. Porphyry’s editorial and logical work, Iamblichus’ defense of theurgy, and Proclus’ systematic metaphysics are not interchangeable additions to Plotinus. They reveal a tradition asking how philosophical reason, inherited revelation, ritual, and communal teaching cooperate in the soul’s return.'
    ],['neoplatonism','platonism','aristotelianism','philosophy-of-religion'],['plotinus'],['Enneads','Categories']),
    section('architecture','The One, Intellect, Soul, and ordered dependence',[
      'The best-known Neoplatonic architecture distinguishes the One, Intellect, and Soul. The One is prior to determinate being because every complex reality depends on unity. Intellect is the living intelligible order of Forms, where thinking and being coincide. Soul receives intelligible order and communicates it through life, nature, and the sensible cosmos. These are not places stacked above the physical universe. They identify relations of explanatory dependence and kinds of activity, each more multiple than what it depends upon.',
      'Later Neoplatonists articulate additional levels and mediations, but the central problem remains stable: how can a first principle explain multiplicity without becoming internally multiple or making plurality unrelated to its source? Procession describes dependence and productive abundance; return describes the orientation through which what proceeds realizes its proper activity. The architecture is hierarchical, but hierarchy here primarily concerns causal and intelligible priority. Its social and political uses require separate scrutiny. A metaphysical order does not automatically justify every human hierarchy that borrows its language.'
    ],['neoplatonism','metaphysics','platonism'],['plotinus','plato'],['Enneads']),
    section('participation','Participation, causation, and a hierarchy of reality',[
      'Participation explains how a lower reality can possess a feature through dependence on a more fundamental source without becoming identical to it. A beautiful thing participates in form and unity; a living thing participates in soul; an intellect possesses determinate being through relation to the first principle. Neoplatonists use participation to avoid two extremes: separating intelligible principles so completely that they cannot explain sensible things, or reducing those principles to patterns that have no reality beyond their instances.',
      'This model produces a hierarchical metaphysics because effects possess their causes in more limited and divided ways. It also creates technical problems. How is a cause present to many effects without being divided? Why does procession yield these levels rather than others? Does participation explain dependence or restate it? Neoplatonic systems answer with increasingly precise principles about remaining, procession, return, and the ways causes are present through their powers. These questions later influence metaphysics of creation, universals, divine ideas, and the relation between finite beings and an unlimited source.'
    ],['neoplatonism','metaphysics','ontology'],['plotinus','augustine','aquinas'],['Enneads']),
    section('ascent','Philosophy as ethical and intellectual ascent',[
      'Neoplatonic metaphysics is inseparable from a way of life because a soul’s attention determines how clearly it participates in intelligible order. Ethical virtue disciplines appetite and action. Purification loosens identification with bodily possession and social status. Dialectic orders concepts and turns thought toward principles. Contemplation allows the soul to recognize Intellect’s unity, while the highest return approaches a source beyond discursive thought. Ascent is therefore not acquisition of secret information but transformation of desire, attention, judgment, and self-understanding.',
      'The language of ascent can suggest escape from the world, yet major Neoplatonists defend the sensible cosmos as ordered and beautiful. The problem is not that bodies exist; it is that the soul mistakes partial and changing goods for complete identity and value. Philosophical return should make lower activities better ordered, not simply despised. Tension remains over how much civic engagement, ordinary relation, and embodied individuality matter at the highest level. The tradition’s practical force lies in making metaphysical claims answerable to what kind of person and attention they cultivate.'
    ],['neoplatonism','ethics','philosophy-of-religion'],['plotinus','augustine'],['Enneads','Confessions']),
    section('theurgy','Theurgy and disagreement over ritual practice',[
      'Theurgy names ritual action understood as divinely grounded and capable of joining participants to higher causes. Iamblichus argues that human reasoning alone cannot complete ascent because embodied souls depend on powers beyond their discursive control. Material symbols, prayers, and inherited rites can be effective not because human technique compels gods, but because divine presence has already ordered the world through correspondences. Theurgy thus extends participation into religious practice and resists an intellectualism that makes salvation the achievement of philosophical elites.',
      'The practice was controversial and is often misunderstood as irrational magic added to philosophy. Its defenders offered a metaphysical account of why ritual matter could mediate divine activity. Critics could still ask how authentic rites are distinguished from superstition, manipulation, or political authority. Plotinus does not give theurgy the role it receives in later schools, so Neoplatonism contains a real disagreement about the sufficiency of contemplation. The issue clarifies a broader question: if the whole person is embodied and socially formed, can intellectual understanding alone accomplish philosophical transformation?'
    ],['neoplatonism','philosophy-of-religion','metaphysics'],['plotinus'],[]),
    section('plato-aristotle','Reading Plato through Aristotle and Aristotle through Plato',[
      'Neoplatonists regarded Plato as the highest philosophical authority, yet Aristotle became indispensable to education and argument. His logic, categories, psychology, and metaphysics supplied tools for clarifying questions that Platonists then placed within a broader hierarchy. Some commentators sought deep harmony between the two thinkers, assigning their apparent disagreements to different levels or purposes. Others acknowledged sharper conflicts. The result is not simple synthesis but a disciplined attempt to decide where Aristotelian analysis applies and where Platonic first principles exceed it.',
      'Porphyry’s work on the Categories became especially influential, while later commentary traditions transmitted both philosophers together. This interaction shaped Islamic, Jewish, Christian, and scholastic thought, sometimes through texts whose authorship was misunderstood. The Theology of Aristotle, derived from Plotinian material, encouraged readers to see Neoplatonic metaphysics as Aristotle’s own highest teaching. The history is a reminder that traditions develop through libraries, translations, curricula, and attribution as well as through arguments. What readers believe a predecessor wrote can redirect centuries of philosophical construction.'
    ],['neoplatonism','platonism','aristotelianism'],['plato','aristotle','plotinus'],['Categories','Metaphysics','Enneads']),
    section('christian','Augustine, Pseudo-Dionysius, and Christian Neoplatonism',[
      'Augustine encountered Platonist books that helped him conceive immaterial reality, inward ascent, and evil as privation rather than an independent substance. He transformed these resources within Christian commitments to creation, incarnation, grace, will, and personal relation to God. The Confessions shows inwardness becoming both philosophical investigation and prayer. Augustine’s Platonism is therefore neither a foreign layer on Christianity nor Plotinus repeated in theological language. The differences alter the meaning of procession, return, time, embodiment, and salvation.',
      'Pseudo-Dionysius develops a Christian Neoplatonic language of hierarchy, divine names, procession, return, and negative theology. God exceeds every affirmation and negation, yet divine goodness is communicated through ordered participation. These writings became enormously influential in Eastern and Western Christianity. They also create tensions: hierarchical mediation can organize spiritual community, but it can be used to naturalize institutional rank. Christian Neoplatonism demonstrates the tradition’s power and risk. Its metaphysics can articulate humility before what exceeds concepts while also lending sacred authority to contested human arrangements.'
    ],['neoplatonism','philosophy-of-religion','platonism'],['augustine','pseudo-dionysius','plotinus'],['Confessions','Mystical Theology']),
    section('islamic-jewish','Jewish and Islamic transformations',[
      'Neoplatonic materials entered Arabic philosophy through translations, adaptations, and texts attributed to Aristotle. Accounts of first principle, intellects, soul, causation, and return interacted with Aristotelian demonstration and theological questions about creation, prophecy, and divine attributes. Al-Farabi and Avicenna developed systems that cannot be classified as merely Aristotelian or Neoplatonic. Their distinctions and arguments transformed subsequent Islamic thought, including thinkers who criticized parts of the philosophical inheritance.',
      'Jewish philosophers likewise adapted themes of unity, emanation, intellect, negative theology, and return within commitments to scripture, law, and community. Maimonides is often read primarily through Aristotelianism, yet his negative theology and account of intellectual perfection belong to a broader field shaped by Neoplatonic and Arabic philosophical developments. These transformations caution against treating Neoplatonism as exclusively Greek or Christian. Its concepts became shared but contested instruments through which multiple traditions negotiated how an utterly first principle relates to a plural, knowable, and morally demanding world.'
    ],['neoplatonism','islamic-philosophy','philosophy-of-religion'],['al-farabi','avicenna','maimonides'],['The Cure','Guide for the Perplexed']),
    section('renaissance-modern','Renaissance Platonism and modern influence',[
      'Renaissance scholars and philosophers renewed access to Platonic and Neoplatonic texts, translating and interpreting Plotinus and later authors within new religious, artistic, and political settings. Themes of cosmic sympathy, beauty, love, intellectual ascent, and human dignity entered debates that cannot be reduced to one revival. Neoplatonic ideas also influenced art theory and accounts of creativity by presenting visible beauty as expression of intelligible form rather than mere imitation of sensible surfaces.',
      'Modern influence appears in idealism, metaphysics, mysticism, romanticism, and negative theology. Thinkers return to Neoplatonic questions whenever they ask whether unity is prior to relation, whether consciousness participates in a more comprehensive intelligibility, or whether ultimate reality can be approached only through limits of language. Such uses are often selective and can detach concepts from their ancient arguments. The tradition remains most philosophically useful when unity, participation, and ascent are treated as claims requiring explanation, not as evocative vocabulary that excuses vagueness.'
    ],['neoplatonism','aesthetics','metaphysics','philosophy-of-religion'],['plotinus','pseudo-dionysius'],['Enneads','Mystical Theology']),
    section('misreadings-reading','Common misreadings and how to begin',[
      'Neoplatonism is not simply otherworldly contempt for bodies. It distinguishes levels of reality while defending the sensible cosmos as ordered expression. It is not a vague mystical mood: its contemplative claims emerge from arguments about unity, causation, intellect, and soul. It is not one fixed doctrine of emanation, since later members disagree about divine orders, ritual, and interpretation. Finally, hierarchy in metaphysics should not be assumed to justify every social hierarchy. Participation and causal priority require arguments distinct from political authority.',
      'Begin with Plotinus on beauty, the virtues, and the principal levels of reality, then read Porphyry’s Life to understand the editorial and practical setting. Move to selections from Iamblichus and Proclus to see why ritual and systematic mediation become more prominent. Compare Augustine or Pseudo-Dionysius with Plotinus while marking transformed commitments, and follow one Jewish or Islamic route without treating it as passive reception. The guiding questions are concrete: what explains plurality without abandoning unity, how is a cause present in its effects, and what practices would make those metaphysical relations ethically significant?'
    ],['neoplatonism','platonism','metaphysics','philosophy-of-religion'],['plotinus','augustine','pseudo-dionysius','avicenna'],['Enneads','Confessions','Mystical Theology'])
  ]
};
